 1	import React, { FC, useCallback } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	import classNames from 'classnames';
 4	
 5	import { ALL_NAMESPACES_SESSION_KEY } from '@kubevirt-utils/hooks/constants';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { ListPageCreateDropdown, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Button, ButtonVariant } from '@patternfly/react-core';
 9	import { createURL } from '@virtualmachines/details/tabs/overview/utils/utils';
10	
11	import useCheckupsNetworkPermissions from './network/hooks/useCheckupsNetworkPermissions';
12	import { useCheckupsStoragePermissions } from './storage/components/hooks/useCheckupsStoragePermissions';
13	import { trimLastHistoryPath } from './utils/utils';
14	
15	const CheckupsRunButton: FC = () => {
16	  const [namespace] = useActiveNamespace();
17	  const navigate = useNavigate();
18	  const location = useLocation();
19	  const { t } = useKubevirtTranslation();
20	  const { isPermitted: isCreateNetworkPermitted } = useCheckupsNetworkPermissions();
21	  const { isPermitted: isCreateStoragePermitted } = useCheckupsStoragePermissions();
22	
23	  const createItems = {
24	    network: (
25	      <div
26	        className={classNames({ 'CheckupsRunButton--item__disabled': !isCreateNetworkPermitted })}
27	      >
28	        {t('Network latency')}
29	      </div>
30	    ),
31	    storage: (
32	      <div
33	        className={classNames({ 'CheckupsRunButton--item__disabled': !isCreateStoragePermitted })}
34	      >
35	        {t('Storage')}
36	      </div>
37	    ),
38	  };
39	
40	  const onCreate = useCallback(
41	    (type: string) => {
42	      switch (type) {
43	        case 'network':
44	          return (
45	            isCreateNetworkPermitted &&
46	            navigate(createURL('network/form', trimLastHistoryPath(location.pathname)))
47	          );
48	        case 'storage':
49	          return (
50	            isCreateStoragePermitted &&
51	            navigate(createURL('storage/form', trimLastHistoryPath(location.pathname)))
52	          );
53	      }
54	    },
55	    [isCreateNetworkPermitted, navigate, location, isCreateStoragePermitted],
56	  );
57	
58	  return (
59	    <Button
60	      className={classNames({
61	        'CheckupsRunButton--main': ALL_NAMESPACES_SESSION_KEY === namespace,
62	      })}
63	      isDisabled={ALL_NAMESPACES_SESSION_KEY === namespace}
64	      variant={ButtonVariant.plain}
65	    >
66	      <ListPageCreateDropdown items={createItems} onClick={onCreate}>
67	        {t('Run checkup')}
68	      </ListPageCreateDropdown>
69	    </Button>
70	  );
71	};
72	
73	export default CheckupsRunButton;

